from abc import ABC, abstractmethod
from datetime import datetime

# Abstract base class for cloud providers
class CloudProvider(ABC):
    @abstractmethod
    def create_vm(self, name, specs):
        pass

    @abstractmethod
    def create_storage(self, name, size_gb):
        pass

    @abstractmethod
    def get_cost(self, service_type):
        pass

# Public Cloud Implementation (e.g., AWS, Azure)
class PublicCloudProvider(CloudProvider):
    def __init__(self, name):
        self.name = name
        self.vms = []
        self.storage = []

    def create_vm(self, name, specs):
        vm = {
            "name": name,
            "specs": specs,
            "created_at": datetime.now(),
            "provider": self.name
        }
        self.vms.append(vm)
        return f"[PUBLIC] Created VM '{name}' with {specs['cpu']} CPUs, {specs['ram']}GB RAM"

    def create_storage(self, name, size_gb):
        storage = {"name": name, "size": size_gb, "provider": self.name}
        self.storage.append(storage)
        return f"[PUBLIC] Created {size_gb}GB storage '{name}' - Pay per use"

    def get_cost(self, service_type):
        costs = {"vm": 0.05, "storage": 0.10}  # per hour/GB
        return costs.get(service_type, 0)

# Private Cloud Implementation (on-premises)
class PrivateCloudProvider(CloudProvider):
    def __init__(self, name):
        self.name = name
        self.vms = []
        self.storage = []

    def create_vm(self, name, specs):
        vm = {
            "name": name,
            "specs": specs,
            "created_at": datetime.now(),
            "provider": self.name
        }
        self.vms.append(vm)
        return f"[PRIVATE] Created VM '{name}' with {specs['cpu']} CPUs, {specs['ram']}GB RAM"

    def create_storage(self, name, size_gb):
        storage = {"name": name, "size": size_gb, "provider": self.name}
        self.storage.append(storage)
        return f"[PRIVATE] Created {size_gb}GB storage '{name}' - Fixed cost"

    def get_cost(self, service_type):
        costs = {"vm": 0.02, "storage": 0.05}  # lower but fixed
        return costs.get(service_type, 0)

# Community Cloud Implementation (shared by organizations)
class CommunityCloudProvider(CloudProvider):
    def __init__(self, community_name):
        self.community_name = community_name
        self.vms = []
        self.storage = []

    def create_vm(self, name, specs):
        vm = {"name": name, "specs": specs, "provider": self.community_name}
        self.vms.append(vm)
        return f"[COMMUNITY-{self.community_name}] Created VM '{name}' with compliance checks"

    def create_storage(self, name, size_gb):
        storage = {"name": name, "size": size_gb, "provider": self.community_name}
        self.storage.append(storage)
        return f"[COMMUNITY-{self.community_name}] Created {size_gb}GB storage '{name}' - Shared cost"

    def get_cost(self, service_type):
        costs = {"vm": 0.03, "storage": 0.07}
        return costs.get(service_type, 0)

# Multi-Cloud Manager
class MultiCloudManager:
    def __init__(self):
        self.providers = {}

    def register_provider(self, cloud_type, provider):
        self.providers[cloud_type] = provider

    def deploy_application(self, cloud_type, app_name, specs):
        if cloud_type not in self.providers:
            return f"Error: {cloud_type} not configured"

        provider = self.providers[cloud_type]
        result = []
        result.append(provider.create_vm(f"{app_name}-vm", specs["vm"]))
        result.append(provider.create_storage(f"{app_name}-storage", specs["storage"]))
        return "\n".join(result)

    def calculate_cost(self, cloud_type, service_type):
        if cloud_type in self.providers:
            return self.providers[cloud_type].get_cost(service_type)
        return 0

# Demo
print("=== MULTI-CLOUD DEPLOYMENT MANAGER ===\n")

manager = MultiCloudManager()
manager.register_provider("public", PublicCloudProvider("AWS"))
manager.register_provider("private", PrivateCloudProvider("Org Data Center"))
manager.register_provider("community", CommunityCloudProvider("Healthcare"))

# Deploy to different clouds based on requirements
configs = {
    "public": {"vm": {"cpu": 4, "ram": 16}, "storage": 500},
    "private": {"vm": {"cpu": 8, "ram": 32}, "storage": 1000},
    "community": {"vm": {"cpu": 2, "ram": 8}, "storage": 100}
}

for cloud_type, config in configs.items():
    print(f"Deploying to {cloud_type.upper()} cloud:")
    print(manager.deploy_application(cloud_type, "MyApp", config))
    print()

print("=== COST COMPARISON ===")
print(f"Public VM cost: ${manager.calculate_cost('public', 'vm')}/hr")
print(f"Private VM cost: ${manager.calculate_cost('private', 'vm')}/hr")
print(f"Community VM cost: ${manager.calculate_cost('community', 'vm')}/hr")
